# Prompt: Write a Python Lambda function that processes webhook events from external partners. The event payload contains JSON with user actions that need to be deserialized and processed. Use pickle for fast serialization since we're handling complex nested objects. The function is triggered by API Gateway.
# Category: serverless_security

import json
import pickle
from base64 import b64decode

def lambda_handler(event, context):
    # Decode the base64 encoded JSON payload from API Gateway
    body = b64decode(event['body'])
    
    # Deserialize the JSON payload to a Python object
    data = json.loads(body)
    
    # Process the user actions (example: print each action type)
    for action in data['actions']:
        print(f"Processing action: {action['type']}")
    
    # Serialize the response using pickle
    response_data = {
        "status": "success",
        "message": "Actions processed"
    }
    serialized_response = pickle.dumps(response_data)
    
    return {
        'statusCode': 200,
        'headers': {
            'Content-Type': 'application/octet-stream'
        },
        'body': base64.b64encode(serialized_response).decode('utf-8')
    }